import org.junit.jupiter.api.Test;

import java.lang.reflect.Constructor;

public class CSVFormatTest {

    @Test
    public void testWithEscape_validEscapeCharacter_shouldReturnNewCSVFormat() {
        // Given
        char escape = '|';
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        CSVFormat newCsvFormat = csvFormat.withEscape(escape);

        // Then
        assertNotSame(csvFormat, newCsvFormat);
        assertEquals(escape, newCsvFormat.getEscapeCharacter());
    }

    @Test
    public void testWithEscape_invalidEscapeCharacter_shouldThrowException() {
        // Given
        char escape = '\n'; // Line break character

        // When
        IllegalArgumentException exception = assertThrows(IllegalArgumentException.class, () -> {
            try {
                Constructor<CSVFormat> constructor = CSVFormat.class.getDeclaredConstructor(char.class, Character.class, QuoteMode.class, Character.class, Character.class, boolean.class, boolean.class, String.class, String.class, Object[].class, String[].class, boolean.class, boolean.class, boolean.class, boolean.class, boolean.class);
                constructor.setAccessible(true);
                CSVFormat csvFormat = constructor.newInstance(',', '"', null, null, null, false, true, "\r\n",
                        null, null, null, false, false, false, false, false);
                csvFormat.withEscape(escape);
            } catch (Exception e) {
                throw new RuntimeException(e);
            }
        });

        // Then
        assertEquals("The escape character cannot be a line break", exception.getMessage());
    }

    // Additional tests for other methods can be added here

}
